def find_Nth_Digit(num1, num2):
    def gcd(a, b):
        while b != 0:
            a, b = b, a % b
        return a

    common_divisor = gcd(num1, num2)
    numerator = num1 // common_divisor
    denominator = num2 // common_divisor
    fraction = f"{numerator}/{denominator}"
    n = (10 ** len(str(fraction)) + 1) * int(nth_digit(fraction))
    return n

def nth_digit(num):
    length = len(str(int(num)))
    if length == 0:
        return '0'
    else:
        return str(int(num)[length - 1])
```

