def rearange_string(s):
    char_count = {}

    # Count the frequency of each character in the string
    for char in s:
        if char in char_count:
            char_count[char] += 1
        else:
            char_count[char] = 1

    # Check if there are any adjacent characters that are different
    for i in range(len(s) - 1):
        if s[i] == s[i + 1] and s[i] not in char_count or s[i + 1] == s[i] and s[i] not in char_count:
            return False

    return True
