def find_Max_Num(digits):
    if not digits:
        return 0

    max_num = int(''.join(map(str, digits)))

    for i in range(max_num, -1, -1):
        num_str = ''
        temp = i

        while temp > 0:
            num_str = str(temp % 10) + num_str
            temp //= 10

        if int(num_str) > max_num:
            max_num = int(num_str)

    return max_num
```

