def count_Substrings():
    def is_valid(s):
        return s.isdigit() and len(s) == int(s)

    def count_substring(s, target_sum):
        if not s:
            return 0

        dp = [0] * (len(s) + 1)
        dp[0] = 1
        for i in range(1, len(s) + 1):
            if is_valid(s[i - 1]):
                dp[i] += dp[i - 1]
            if int(s[:i]) == target_sum:
                dp[i] += dp[i - 1]

        return dp[-1]

    n = input("Enter the length of string: ")
    target_sum = int(input("Enter the sum of digits: "))
    print(count_substring(n, target_sum))
```

